from Crypto.Cipher import AES
from Crypto.Random import get_random_bytes
from Crypto import PKCS12 as pkcs12
import os

def load_key():
    with open('config.txt', 'rb') as f:
        key = pkcs12.load_keyfile(f, password='your_password'.encode())
    return key

def encrypt(key, data):
    cipher = AES.new(key, AES.MODE_EAX)
    nonce = cipher.nonce
    ciphertext = cipher.encrypt(data)
    tag = cipher.tag
    return nonce + ciphertext + tag

def decrypt(key, encrypted_data):
    nonce, ciphertext, tag = encrypted_data
    cipher = AES.new(key, AES.MODE_EAX, nonce)
    cipher.verify(tag)
    return cipher.decrypt(ciphertext)

def encrypt_card_number(card_number):
    key = load_key()
    encrypted = encrypt(key, card_number.encode())
    return encrypted

def decrypt_card_number(encrypted):
    key = load_key()
    decrypted = decrypt(key, encrypted)
    return decrypted.decode('utf-8')